initial_checklist:
[
    {
        "name": "search_emails",
        "required parameters": {"query": "shared document"},
        "conditions": null
    },
    {
        "name": "download_file_through_id",
        "required parameters": {"file_id": null, "save_dir": "/downloads"},
        "conditions": "{'file_id': 'search_emails'}"
    },
    {
        "name": "read_file",
        "required parameters": {"path": "/downloads/document_name"},  // The actual document name will be obtained after downloading it
        "conditions": "{'path': 'download_file_through_id'}"
    },
    {
        "name": "create_file",
        "required parameters": {"path": "/downloads/summary.txt", "content": null},  // Content will depend on the read_file function output
        "conditions": "{'content': 'read_file'}"
    },
    {
        "name": "send_email",
        "required parameters": {"recipients": ["lily@example.com"], "subject": "Summary of Shared Document", "body": null},
        "conditions": "{'body': 'create_file'}"
    }
]
